import Mathlib

def correct_version (w : Nat) : Bool :=
  let is_divisible := true;
  if w < 4 then
    false
  else
    let mut i := 0;
    while i < w do
      i := i + 2;
    if i != w then
      false
    else
      true

def student_version (w : Nat) : Bool :=
  let is_divisible := true;
  if w < 4 then
    false
  else
    let mut i := 0;
    while i < w do
      i := i + 2;
    if i != w then
      false
    else
      true

theorem correct_version_eq_student_version (w : Nat) (h : w > 0 ∧ w < 10000000) : correct_version w = student_version w :=
begin
  unfold correct_version student_version,
  by_cases h1 : w < 4,
  { simp [h1] },
  { have h2 : w % 2 = 0 := by {
      have h3 : w % 2 = 0 ∨ w % 2 = 1 := Nat.mod_two_eq_zero_or_one w,
      cases h3,
      { exact h3 },
      { have h4 : w % 2 = 1 := h3,
        have h5 : w = 2 * (w / 2) + 1 := Nat.mod_add_div w 2,
        rw [h5, Nat.mul_comm],
        have h6 : 2 * (w / 2) + 1 < 4 := by {
          rw [Nat.add_comm],
          exact Nat.mul_lt_mul_left (by norm_num : 0 < 2) (by linarith : w / 2 < 2),
        },
        have h7 : w < 4 := by {
          rw [h5],
          linarith,
        },
        contradiction,
      },
    },
    simp [h2] }
end

def main : IO Unit :=
do
  let w := IO.randomNatLt 10000000,
  let is_divisible1 := correct_version w,
  let is_divisible2 := student_version w,
  IO.println s!"w = {w}, is_divisible1 = {is_divisible1}, is_divisible2 = {is_divisible2}",
  if is_divisible1 = is_divisible2 then
    IO.println "Assertion holds"
  else
    IO.println "Assertion fails"
```
===END LEAN PROOF===

