import Mathlib

-- Define the bubble sort function in Lean
def bubbleSort (size : Nat) (item : Array Int) : Array Int := 
  let rec innerBubbleSort (a : Nat) (item : Array Int) : Array Int := 
    if a < size then
      let rec innerSwap (b : Nat) (item : Array Int) : Array Int := 
        if b >= a then
          if b - 1 < size && b < size then
            if item.get! (b - 1) > item.get! b then
              let t := item.get! (b - 1);
              let item' := item.set! (b - 1) (item.get! b);
              let item'' := item'.set! b t;
              innerSwap (b - 1) item''
            else
              innerSwap (b - 1) item
          else
            innerSwap (b - 1) item
        else
          innerBubbleSort (a + 1) item
      innerBubbleSort (a + 1) item
    else
      item
  innerBubbleSort 1 item

-- Define the insertion sort function in Lean
def insertionSort (size : Nat) (item : Array Int) : Array Int := 
  let rec innerInsertionSort (j : Nat) (item : Array Int) : Array Int := 
    if j < size then
      let pivot := item.get! j;
      let rec innerShift (i : Nat) (item : Array Int) : Array Int := 
        if i >= 0 ∧ item.get! i > pivot then
          let item' := item.set! (i + 1) (item.get! i);
          innerShift (i - 1) item'
        else
          item.set! (i + 1) pivot
      innerInsertionSort (j + 1) (innerShift (j - 1) item)
    else
      item
  innerInsertionSort 1 item

-- Define the main function in Lean
def q1 (argc : Nat) (argv : Array String) : IO Unit := do
  if argc < 2 then
    return ()
  else
    let N := IO.FS.Stream.ofString "N" |>.getRandomInt;
    let mut a := #[];
    for i in [:N] do
      a := a.push 0;
    match 2 with
    | 0 => 
      for i in [:N] do
        a := a.set! i i;
    | 1 => 
      for i in [N-1 : 0] do
        a := a.set! i (N - 1 - i);
    | 2 => 
      for i in [:N] do
        a := a.set! i i;
      for i in [:N] do
        let r := i + (IO.FS.Stream.ofString "N" |>.getRandomInt % (N - i));
        let temp := a.get! i;
        a := a.set! i (a.get! r);
        a := a.set! r temp;
    let sorted := bubbleSort N a;
    return ()

-- Main entry point
def main (argc : Nat) (argv : Array String) : IO Unit := do
  q1 argc argv;
  return ()

-- Define the property checks in Lean
def checkProperty (main : IO Unit) : IO Unit := do
  -- The following checks are placeholders for the actual property checks.
  -- In Lean, these checks would typically be formalized as theorems or lemmas.
  -- For the purpose of this example, we will just print a message.
  IO.println "Property checks are not implemented in this proof."
  return ()

-- Check the properties
#eval checkProperty main
