```lean
import Mathlib

-- Define the property and the loop invariants
def bob : Nat := 13
def samantha : Nat := 17

-- Define the loop invariant
def loopInvariant (bob samantha : Nat) : Prop :=
  bob + samantha < 100

-- Define the loop body
def loopBody (bob samantha : Nat) : (Nat × Nat) :=
  let temp := bob;
  (samantha, temp)

-- Define the loop termination condition
def loopTerminationCondition (bob samantha : Nat) : Bool :=
  bob + samantha ≥ 100

-- Define the main function
def main : Nat × Nat :=
  let mut bob := 13;
  let mut samantha := 17;
  while loopTerminationCondition bob samantha = false do
    let (bob', samantha') := loopBody bob samantha;
    bob := bob';
    samantha := samantha';
  (bob, samantha)

-- Prove the loop terminates
theorem loopTerminates : ∃ (bob samantha : Nat), loopTerminationCondition bob samantha = true :=
begin
  -- Base case: initial values of bob and samantha
  have h0 : loopInvariant 13 17 := by simp [loopInvariant];
  -- Induction step: loop body preserves the invariant
  have h1 : ∀ (bob samantha : Nat), loopInvariant bob samantha → loopInvariant (loopBody bob samantha).1 (loopBody bob samantha).2 :=
    by intros; simp [loopInvariant, loopBody];
  -- Termination condition is eventually met
  have h2 : ∀ (bob samantha : Nat), loopInvariant bob samantha → ∃ (n : Nat), loopTerminationCondition (loopBody^n bob samantha).1 (loopBody^n bob samantha).2 = true :=
    by intros; induction n with
    | zero => simp [loopTerminationCondition, loopBody];
    | succ n ih => simp [loopTerminationCondition, loopBody];
  -- Conclusion
  exact exists.intro 13 (exists.intro 17 h2);
end

-- Prove the property
theorem mainProperty : loopTerminationCondition (main).1 (main).2 = true :=
begin
  simp [main, loopTerminates];
end
```
===END LEAN PROOF===

